   307→namespace fl360::infra::metrics {
   308→
   309→class EventMetricsSink
   310→{
   311→public:
   312→    explicit EventMetricsSink(core::EventBus& bus)
   313→    {
   314→        bus.subscribe<domain::SecurityCommand>(
   315→            [this](const domain::SecurityCommand& cmd) {
   316→                std::cout << "[METRICS] Command: " << cmd.name()
   317→                          << " tenant=" << cmd.tenantId << '\n';
   318→            });
   319→    }
   320→};
   321→
   322→} // namespace fl360::infra::metrics
   323→```
   324→
   325→---
   326→
   327→## 5.  Service Mesh – gRPC Skeleton (mutual-TLS ready)
   328→
   329→```cpp
   330→// proto/backupnode.proto
   331→/*
   332→syntax = "proto3";
   333→package fl360.backupnode;
   334→service BackupNode {
   335→  rpc RollClusterBackup(RollClusterBackupRequest) returns (BackupStatus);
   336→}
   337→message RollClusterBackupRequest {
   338→  string tenant_id = 1;
   339→  bool   offsite   = 2;
   340→}
   341→message BackupStatus {
   342→  bool   ok      = 1;
   343→  string message = 2;
   344→}
   345→*/
   346→```
   347→
   348→```cpp
   349→// src/backupnode/BackupNodeService.cpp
   350→#include "backupnode.grpc.pb.h"
   351→#include <grpcpp/grpcpp.h>
   352→#include <iostream>
   353→
   354→namespace fl360::infra {
   355→
   356→class BackupNodeService final : public backupnode::BackupNode::Service
   357→{
   358→public:
   359→    grpc::Status RollClusterBackup(
   360→        grpc::ServerContext* ctx,
   361→        const backupnode::RollClusterBackupRequest* req,
   362→        backupnode::BackupStatus* rsp) override
   363→    {
   364→        std::cout << "[BACKUP] rolling backup for " << req->tenant_id() << '\n';
   365→        rsp->set_ok(true);
   366→        rsp->set_message("Backup scheduled");
   367→        return grpc::Status::OK;
   368→    }
   369→};
   370→
   371→} // namespace fl360::infra
   372→```
   373→
   374→---
   375→
   376→## 6.  Wiring It Together – `main.cpp`
   377→
   378→```cpp
   379→// src/main.cpp
   380→#include "EventBus.hpp"
   381→#include "commands/SecurityCommand.hpp"
   382→#include "scan/ScanRegistry.hpp"
   383→#include "scan/IScanStrategy.hpp"
   384→#include "policy/PolicyValidator.hpp"
   385→#include "metrics/EventMetricsSink.hpp"
   386→
   387→#include <iostream>
   388→
   389→using namespace fl360;
   390→
   391→int main()
   392→{
   393→    core::EventBus bus;
   394→    infra::metrics::EventMetricsSink metrics{bus};
   395→
   396→    // Register strategies
   397→    domain::ScanRegistry registry;
   398→    registry.registerStrategy<domain::ContinuousScanStrategy>();
   399→    registry.registerStrategy<domain::PayAsYouGoScanStrategy>();
   400→
   401→    // Build policy chain
   402→    domain::PolicyValidator::Ptr policies =
   403→        std::make_unique<domain::IsTenantActive>(
   404→            std::make_unique<domain::MeetsSLAPolicy>());
   405→
   406→    // Subscribe orchestrator to security commands
   407→    bus.subscribe<domain::InitiateSecurityScan>([&](const auto& cmd) {
   408→        domain::SecurityContext ctx;
   409→        policies->validate(ctx);
   410→        if (!ctx.reason.empty()) {
   411→            std::cerr << "[ERROR] " << ctx.reason << '\n';
   412→            return;
   413→        }
   414→        auto& engine = registry.resolve("continuous");
   415→        engine.execute(cmd.tenantId);
   416→    });
   417→
   418→    // Publish a command
   419→    domain::InitiateSecurityScan scanCmd;
   420→    scanCmd.tenantId = "acme-corp";
   421→    scanCmd.depth    = domain::InitiateSecurityScan::ScanDepth::kDeep;
   422→    bus.publish(scanCmd);
   423→
   424→    return 0;
   425→}
   426→```
   427→
   428→Build & Run:
   429→
   430→```bash
   431→g++ -std=c++17 -pthread -Iinclude src/main.cpp -o fl360
   432→./fl360
   433→```
   434→
   435→Expected output:
   436→
   437→```
   438→[METRICS] Command: InitiateSecurityScan tenant=acme-corp
   439→[SCAN] Continuous scan for acme-corp
   440→```
   441→
   442→---
   443→
   444→## 7.  Key Takeaways
   445→• Single-header EventBus keeps the Domain pure and testable.  
   446→• Strategy registry allows per-tenant customization without redeploy.  
   447→• Policy chain enforces compliance before any privileged action.  
   448→• Observers stream metrics/logs with zero coupling.  
   449→• gRPC services participate in Istio service-mesh with mutual-TLS.  
   450→
   451→> FortiLedger360 combines proven patterns into a cohesive, maintainable security platform ready for enterprise scale.

