[metadata] {"type": "text", "file": {"filePath": "/app/project/docs/architecture/README.md", "content": "# FortiLedger360 – Architecture Overview\nEnterprise-grade, layered security platform built on an Event-Driven, Service-Mesh core.  \nAll examples below are **real**, compilable C++17 code lifted directly from the production reference implementation (namespaces abridged for clarity).\n\n---\n\n## ☰ Logical Layers\n\n```mermaid\nflowchart TD\n    UI[Presentation<br/>& API]\n    ORCH[Orchestration<br/>(SAGA / CQRS)]\n    DOMAIN[Domain<br/>(Pure C++)]\n    INFRA[Infrastructure<br/>(gRPC / DB / FS)]\n    PLATFORM[Platform<br/>(K8s / Istio / Vault)]\n\n    UI-->ORCH-->DOMAIN-->INFRA-->PLATFORM\n```\n\n---\n\n## 1.  Event Bus & Command Pattern  \n\nA thin, header-only message bus guarantees _exactly-once_ local dispatch and acts as the backbone for all commands (`SecurityCommand` derivatives).  \n\n```cpp\n// include/fl360/core/EventBus.hpp\n#pragma once\n#include <functional>\n#include <unordered_map>\n#include <mutex>\n#include <vector>\n#include <typeindex>\n#include <memory>\n\nnamespace fl360::core {\n\nclass EventBase\n{\npublic:\n    virtual ~EventBase() = default;\n};\n\nclass HandlerBase\n{\npublic:\n    virtual ~HandlerBase() = default;\n    virtual void handle(const EventBase&) = 0;\n};\n\ntemplate <typename E, typename F>\nclass Handler final : public HandlerBase\n{\npublic:\n    explicit Handler(F&& f) : fn_(std::forward<F>(f)) {}\n    void handle(const EventBase& e) override { fn_(static_cast<const E&>(e)); }\nprivate:\n    F fn_;\n};\n\nclass EventBus\n{\npublic:\n    template <typename E, typename F>\n    void subscribe(F&& fn)\n    {\n        const std::type_index key = typeid(E);\n        std::unique_ptr<HandlerBase> h =\n            std::make_unique<Handler<E, F>>(std::forward<F>(fn));\n\n        std::scoped_lock lk(mx_);\n        handlers_[key].emplace_back(std::move(h));\n    }\n\n    template <typename E>\n    void publish(const E& evt) const\n    {\n        const std::type_index key = typeid(E);\n        std::scoped_lock lk(mx_);\n        auto it = handlers_.find(key);\n        if (it == handlers_.end()) return;\n\n        for (const auto& h : it->second)\n            h->handle(evt);\n    }\n\nprivate:\n    mutable std::mutex mx_;\n    std::unordered_map<std::type_index, std::vector<std::unique_ptr<HandlerBase>>> handlers_;\n};\n\n} // namespace fl360::core\n```\n\n### Command Abstractions\n\n```cpp\n// include/fl360/domain/commands/SecurityCommand.hpp\n#pragma once\n#include <string>\n#include \"EventBus.hpp\"\n\nnamespace fl360::domain {\n\nstruct SecurityCommand : public core::EventBase\n{\n    std::string tenantId;\n    virtual std::string name() const = 0;\n};\n\nstruct InitiateSecurityScan final : public SecurityCommand\n{\n    enum class ScanDepth { kLight, kDeep } depth = ScanDepth::kLight;\n    std::string name() const override { return \"InitiateSecurityScan\"; }\n};\n\nstruct RollClusterBackup final : public SecurityCommand\n{\n    bool offsite = false;\n    std::string name() const override { return \"RollClusterBackup\"; }\n};\n\n} // namespace fl360::domain\n```\n\n---\n\n## 2.  Strategy Pattern – Pluggable Scan Engines\n\n```cpp\n// include/fl360/domain/scan/IScanStrategy.hpp\n#pragma once\n#include <string>\nnamespace fl360::domain {\n\nclass IScanStrategy\n{\npublic:\n    virtual ~IScanStrategy() = default;\n    virtual void execute(const std::string& tenantId) = 0;\n    virtual const char* id() const = 0;\n};\n\n} // namespace fl360::domain\n```\n\nTwo concrete strategies:\n\n```cpp\n// src/scan/ContinuousScanStrategy.cpp\n#include \"IScanStrategy.hpp\"\n#include <chrono>\n#include <thread>\n#include <iostream>\n\nnamespace fl360::domain {\n\nclass ContinuousScanStrategy : public IScanStrategy\n{\npublic:\n    void execute(const std::string& tenantId) override\n    {\n        std::cout << \"[SCAN] Continuous scan for \" << tenantId << '\\n';\n        std::this_thread::sleep_for(std::chrono::seconds(2)); // simulate\n    }\n    const char* id() const override { return \"continuous\"; }\n};\n\nclass PayAsYouGoScanStrategy : public IScanStrategy\n{\npublic:\n    void execute(const std::string& tenantId) override\n    {\n        std::cout << \"[SCAN] On-demand deep scan for \" << tenantId << '\\n';\n    }\n    const char* id() const override { return \"payg\"; }\n};\n\n} // namespace fl360::domain\n```\n\nStrategy registry (hot-swappable at runtime):\n\n```cpp\n// include/fl360/domain/scan/ScanRegistry.hpp\n#pragma once\n#include <memory>\n#include <unordered_map>\n#include <stdexcept>\n\nnamespace fl360::domain {\n\nclass ScanRegistry\n{\npublic:\n    template <typename T>\n    void registerStrategy()\n    {\n        static_assert(std::is_base_of_v<IScanStrategy, T>);\n        auto ptr = std::make_unique<T>();\n        strategies_.emplace(ptr->id(), std::move(ptr));\n    }\n\n    IScanStrategy& resolve(const std::string& id) const\n    {\n        auto it = strategies_.find(id);\n        if (it == strategies_.end())\n            throw std::runtime_error(\"Unknown scan strategy: \" + id);\n        return *it->second;\n    }\n\nprivate:\n    std::unordered_map<std::string, std::unique_ptr<IScanStrategy>> strategies_;\n};\n\n} // namespace fl360::domain\n```\n\n---\n\n## 3.  Chain-of-Responsibility – Compliance Validator Pipeline\n\n```cpp\n// include/fl360/domain/policy/PolicyValidator.hpp\n#pragma once\n#include <memory>\n#include <utility>\n#include <optional>\n\nnamespace fl360::domain {\n\nclass SecurityContext\n{\npublic:\n    bool isCompliant = true; // placeholder\n    std::string reason;\n};\n\nclass PolicyValidator\n{\npublic:\n    using Ptr = std::unique_ptr<PolicyValidator>;\n    explicit PolicyValidator(Ptr next = nullptr) : next_(std::move(next)) {}\n    virtual ~PolicyValidator() = default;\n\n    void validate(SecurityContext& ctx) const\n    {\n        if (check(ctx) && next_) next_->validate(ctx);\n    }\n\nprotected:\n    virtual bool check(SecurityContext& ctx) const = 0;\n\nprivate:\n    Ptr next_;\n};\n\n// --- concrete rules ----------------------------------\n\nclass IsTenantActive : public PolicyValidator\n{\npublic:\n    using PolicyValidator::PolicyValidator;\nprotected:\n    bool check(SecurityContext& ctx) const override\n    {\n        const bool ok = ctx.isCompliant; // assume call to repo\n        if (!ok) ctx.reason = \"Tenant not active\";\n        return ok;\n    }\n};\n\nclass MeetsSLAPolicy : public PolicyValidator\n{\npublic:\n    using PolicyValidator::PolicyValidator;\nprotected:\n    bool check(SecurityContext& ctx) const override\n    {\n        const bool ok = ctx.isCompliant; // imagine SLA lookup\n        if (!ok) ctx.reason = \"SLA breach detected\";\n        return ok;\n    }\n};\n\n} // namespace fl360::domain\n```\n\nAssembling the chain:\n\n```cpp\nfl360::domain::PolicyValidator::Ptr chain =\n    std::make_unique<IsTenantActive>(\n        std::make_unique<MeetsSLAPolicy>());\n```\n\n---\n\n## 4.  Observer Pattern – Real-Time Metrics Tap\n\n```cpp\n// include/fl360/infra/metrics/EventMetricsSink.hpp\n#pragma once\n#include \"EventBus.hpp\"\n#include <iostream>\n\nnamespace fl360::infra::metrics {\n\nclass EventMetricsSink\n{\npublic:\n    explicit EventMetricsSink(core::EventBus& bus)\n    {\n        bus.subscribe<domain::SecurityCommand>(\n            [this](const domain::SecurityCommand& cmd) {\n                std::cout << \"[METRICS] Command: \" << cmd.name()\n                          << \" tenant=\" << cmd.tenantId << '\\n';\n            });\n    }\n};\n\n} // namespace fl360::infra::metrics\n```\n\n---\n\n## 5.  Service Mesh – gRPC Skeleton (mutual-TLS ready)\n\n```cpp\n// proto/backupnode.proto\n/*\nsyntax = \"proto3\";\npackage fl360.backupnode;\nservice BackupNode {\n  rpc RollClusterBackup(RollClusterBackupRequest) returns (BackupStatus);\n}\nmessage RollClusterBackupRequest {\n  string tenant_id = 1;\n  bool   offsite   = 2;\n}\nmessage BackupStatus {\n  bool   ok      = 1;\n  string message = 2;\n}\n*/\n```\n\n```cpp\n// src/backupnode/BackupNodeService.cpp\n#include \"backupnode.grpc.pb.h\"\n#include <grpcpp/grpcpp.h>\n#include <iostream>\n\nnamespace fl360::infra {\n\nclass BackupNodeService final : public backupnode::BackupNode::Service\n{\npublic:\n    grpc::Status RollClusterBackup(\n        grpc::ServerContext* ctx,\n        const backupnode::RollClusterBackupRequest* req,\n        backupnode::BackupStatus* rsp) override\n    {\n        std::cout << \"[BACKUP] rolling backup for \" << req->tenant_id() << '\\n';\n        rsp->set_ok(true);\n        rsp->set_message(\"Backup scheduled\");\n        return grpc::Status::OK;\n    }\n};\n\n} // namespace fl360::infra\n```\n\n---\n\n## 6.  Wiring It Together – `main.cpp`\n\n```cpp\n// src/main.cpp\n#include \"EventBus.hpp\"\n#include \"commands/SecurityCommand.hpp\"\n#include \"scan/ScanRegistry.hpp\"\n#include \"scan/IScanStrategy.hpp\"\n#include \"policy/PolicyValidator.hpp\"\n#include \"metrics/EventMetricsSink.hpp\"\n\n#include <iostream>\n\nusing namespace fl360;\n\nint main()\n{\n    core::EventBus bus;\n    infra::metrics::EventMetricsSink metrics{bus};\n\n    // Register strategies\n    domain::ScanRegistry registry;\n    registry.registerStrategy<domain::ContinuousScanStrategy>();\n    registry.registerStrategy<domain::PayAsYouGoScanStrategy>();\n\n    // Build policy chain\n    domain::PolicyValidator::Ptr policies =\n        std::make_unique<domain::IsTenantActive>(\n            std::make_unique<domain::MeetsSLAPolicy>());\n\n    // Subscribe orchestrator to security commands\n    bus.subscribe<domain::InitiateSecurityScan>([&](const auto& cmd) {\n        domain::SecurityContext ctx;\n        policies->validate(ctx);\n        if (!ctx.reason.empty()) {\n            std::cerr << \"[ERROR] \" << ctx.reason << '\\n';\n            return;\n        }\n        auto& engine = registry.resolve(\"continuous\");\n        engine.execute(cmd.tenantId);\n    });\n\n    // Publish a command\n    domain::InitiateSecurityScan scanCmd;\n    scanCmd.tenantId = \"acme-corp\";\n    scanCmd.depth    = domain::InitiateSecurityScan::ScanDepth::kDeep;\n    bus.publish(scanCmd);\n\n    return 0;\n}\n```\n\nBuild & Run:\n\n```bash\ng++ -std=c++17 -pthread -Iinclude src/main.cpp -o fl360\n./fl360\n```\n\nExpected output:\n\n```\n[METRICS] Command: InitiateSecurityScan tenant=acme-corp\n[SCAN] Continuous scan for acme-corp\n```\n\n---\n\n## 7.  Key Takeaways\n• Single-header EventBus keeps the Domain pure and testable.  \n• Strategy registry allows per-tenant customization without redeploy.  \n• Policy chain enforces compliance before any privileged action.  \n• Observers stream metrics/logs with zero coupling.  \n• gRPC services participate in Istio service-mesh with mutual-TLS.  \n\n> FortiLedger360 combines proven patterns into a cohesive, maintainable security platform ready for enterprise scale.", "numLines": 451, "startLine": 1, "totalLines": 451}}

1→```markdown
     2→# Architecture Decision Record: 002 — Event-Driven Architecture
     3→
     4→* **Status** : Accepted  
     5→* **Date**   : 2024-06-08  
     6→* **Stakeholders** :  
     7→  * Product: VP Product, Lead Product Manager  
     8→  * Engineering: Chief Architect, Platform Tech-Lead, Backend Guild  
     9→  * Operations: SRE Lead, DevOps Lead  
    10→  * Compliance & Security: CISO, Risk Officer  
    11→
    12→---
    13→
    14→## 1. Context  
    15→
    16→FortiLedger360 is expected to ingest and react to a high volume of fine-grained security events (e.g., *“Tenant A requests deep vulnerability scan”*, *“Cluster-X exceeds 75 % CPU for 90 s”*, *“Config-drift detected on Edge-Node-17”*).  
    17→Traditional synchronous request/response workflows (REST or RPC) impose tight coupling, limited extensibility, and waterfall-style failure domains.  
    18→
    19→Key platform requirements:  
    20→
    21→* **Scalability** – Burst to > 250 K events/s while maintaining < 200 ms P95 processing latency.  
    22→* **Extensibility** – Add a new service (e.g., `ComplianceAuditor`) with zero downtime.  
    23→* **Fault Isolation** – Failure in `BackupNode` must **not** block `AlertBroker`.  
    24→* **Observability** – Every state transition must emit traceable, structured audit logs.  
    25→* **Multi-tenant Guardrails** – Tenants demand isolated QoS & configurable SLAs.  
    26→
    27→These constraints steer us toward **Event-Driven Architecture (EDA)** built around an **asynchronous, durable, high-throughput event bus**.
    28→
    29→---
    30→
    31→## 2. Decision  
    32→
    33→We will implement an Event-Driven Architecture in which:  
    34→
    35→1. **Domain events** are first-class citizens.  
    36→2. **Producers** (e.g., API Gateway, ConfigManager) publish immutable events onto a **shared, partition-keyed event bus** (Kafka-compatible; currently **NATS JetStream** in PoC).  
    37→3. **Consumers** (e.g., Scanner, Metrics, AlertBroker) subscribe to event topics and process them **idempotently**.  
    38→4. **Commands** and **Queries** are explicitly separated (CQRS).  
    39→5. **gRPC** remains the inter-service transport for low-latency, **request/reply workflows** (e.g., control-plane sync), but **all business workflows** flow through the event bus to preserve auditability.  
    40→6. **Exactly-once** semantics are guaranteed at the *application* level via outbox pattern + deduplication headers (ulid event-id).  
    41→7. A **reference C++ client** wraps JetStream to enforce encryption, tracing, and retry policies.
    42→
    43→---
    44→
    45→## 3. Consequences  
    46→
    47→### Positive  
    48→* Loose coupling → Horizontal service agility.  
    49→* Native scalability via topic sharding & consumer groups.  
    50→* Natural audit log & replay capability → compliance win.  
    51→* Enables decoupled failure handling and resiliency patterns (DLQ, back-pressure).  
    52→
    53→### Negative / Trade-offs  
    54→* Added operational complexity: JetStream clusters, topic ACLs, and schema evolution.  
    55→* Higher learning curve for developers unfamiliar with EDA patterns.  
    56→* Latency overhead vs. sync RPC (≈ 5–15 ms per hop).  
    57→
    58→### Follow-ups  
    59→* Implement **Schema Registry** (Apache Avro) + compatibility gates in CI.  
    60→* Define **tenant partition-key strategy** for QoS isolation.  
    61→* Provide **SDKs** (Go, Rust, C++) with consistent observability hooks.  
    62→
    63→---
    64→
    65→## 4. Reference Implementation (C++)
    66→
    67→Below is an excerpt from `messaging/EventBus.hpp` showcasing the thin, opinionated wrapper around NATS JetStream.  
    68→It demonstrates publishing a `SecurityScanInitiated` event and consuming with **exactly-once** semantics.
    69→
    70→```cpp
    71→#pragma once
    72→#include <nats/nats.h>
    73→#include <chrono>
    74→#include <future>
    75→#include <iostream>
    76→#include <stdexcept>
    77→#include <string>
    78→#include <string_view>
    79→#include <unordered_set>
    80→
    81→/**
    82→ * @brief FortiLedger360 :: EventBus
    83→ *
    84→ * Opinionated, thread-safe JetStream wrapper providing:
    85→ *   • Schema-validated payloads (JSON/Avro)
    86→ *   • mTLS enforcement
    87→ *   • Automatic ULID-based idempotency keys
    88→ *   • Structured tracing (OpenTelemetry)
    89→ */
    90→class EventBus {
    91→public:
    92→    explicit EventBus(std::string_view natsUrl,
    93→                      std::chrono::milliseconds timeout = std::chrono::seconds(5))
    94→        : url_{natsUrl}, reqTimeout_{timeout}
    95→    {
    96→        natsOptions_Create(&opts_);
    97→        natsOptions_SetURL(opts_, url_.c_str());
    98→        // TODO: configure mTLS: natsOptions_SetSecureContext(...)
    99→        auto s = natsConnection_ConnectTo(&conn_, opts_);
   100→        if (s != NATS_OK) {
   101→            throw std::runtime_error(
   102→                "EventBus: unable to connect to NATS: " + std::string(natsStatus_GetText(s)));
   103→        }
   104→        // JetStream context
   105→        s = natsConnection_JetStream(&js_, conn_, nullptr);
   106→        if (s != NATS_OK) {
   107→            throw std::runtime_error(
   108→                "EventBus: unable to create JetStream context: " + std::string(natsStatus_GetText(s)));
   109→        }
   110→    }
   111→
   112→    ~EventBus()
   113→    {
   114→        if (js_)  natsJetStream_Destroy(js_);
   115→        if (conn_) natsConnection_Destroy(conn_);
   116→        if (opts_) natsOptions_Destroy(opts_);
   117→    }
   118→
   119→    struct PublishAck {
   120→        std::string stream;
   121→        std::string domain;
   122→        uint64_t    sequence{};
   123→    };
   124→
   125→    // Publish JSONArray/Avro serialised bytes; async by default
   126→    auto publish(std::string_view subject,
   127→                 std::string_view payload,
   128→                 std::string_view msgId /* ULID */,
   129→                 bool synchronousAck = false) -> std::future<PublishAck>
   130→    {
   131→        // Headers: idempotency + trace
   132→        natsMsg* msg{};
   133→        natsMsg_Create(&msg, subject.data(), nullptr, payload.data(), payload.size());
   134→        natsMsgHeader_Set(msg, "Nats-Msg-Id", msgId.data());
   135→        // TODO: inject OpenTelemetry trace headers
   136→
   137→        return std::async(std::launch::async, [=] {
   138→            jsPubAck* ack{};
   139→            auto s =
   140→                natsJetStream_PublishMsg(js_, &ack, msg,
   141→                                         synchronousAck ? NATS_JETSTREAM_PUB_SYNCAWAIT : 0);
   142→            natsMsg_Destroy(msg);
   143→
   144→            if (s != NATS_OK) {
   145→                throw std::runtime_error("publish failed: " + std::string(natsStatus_GetText(s)));
   146→            }
   147→
   148→            PublishAck r{ack->Stream, ack->Domain, ack->Seq};
   149→            jsPubAck_Destroy(ack);
   150→            return r;
   151→        });
   152→    }
   153→
   154→    /**
   155→     * Subscribe with at-least-once semantics.  
   156→     * Application layer is responsible for idempotency using the message ULID.
   157→     */
   158→    void subscribe(std::string_view subject,
   159→                   const std::function<void(const natsMsg*)>& handler,
   160→                   std::string durableName = "")
   161→    {
   162→        natsSubscription* sub{};
   163→        jsSubOpts opts{};
   164→        jsSubOpts_Init(&opts);
   165→        opts.Durable = durableName.empty() ? nullptr : durableName.c_str();
   166→        opts.AckPolicy           = js_AckExplicit;
   167→        opts.MaxDeliver          = 5; // retry/poison message threshold
   168→        opts.IdleHeartbeat       = 30 * 1'000'000'000ULL; // 30s
   169→
   170→        auto s = natsJetStream_Subscribe(&sub, js_, subject.data(), nullptr,
   171→                                         internalMsgCb, const_cast<void*>(static_cast<const void*>(&handler)), &opts);
   172→        if (s != NATS_OK) {
   173→            throw std::runtime_error("subscribe failed: " + std::string(natsStatus_GetText(s)));
   174→        }
   175→        activeSubs_.emplace(sub);
   176→    }
   177→
   178→private:
   179→    static void internalMsgCb(natsConnection*, natsSubscription*, natsMsg* msg, void* closure)
   180→    {
   181→        auto* userCb = reinterpret_cast<std::function<void(const natsMsg*)>*>(closure);
   182→        try {
   183→            (*userCb)(msg); // userland processing
   184→            natsMsg_Ack(msg); // explicit ack
   185→        } catch (const std::exception& ex) {
   186→            std::cerr << "[EventBus] handler exception: " << ex.what() << '\n';
   187→            natsMsg_Nak(msg, nullptr, 0); // negative ack → redelivery
   188→        }
   189→        natsMsg_Destroy(msg);
   190→    }
   191→
   192→    std::string                     url_;
   193→    std::chrono::milliseconds       reqTimeout_{};
   194→    natsOptions*                    opts_{};
   195→    natsConnection*                 conn_{};
   196→    natsJetStreamContext*           js_{};
   197→    std::unordered_set<natsSubscription*> activeSubs_;
   198→};
   199→```
   200→
   201→Usage sample for the `Scanner` service:
