   212→    bus.publish(
   213→        "security.scan.initiated",
   214→        R"({"tenant":"acme","cluster":"edge-a1","depth":"deep"})",
   215→        ulid)
   216→        .get(); // wait for ack
   217→
   218→    // Consumer side: listen for completion
   219→    bus.subscribe("security.scan.completed", [](const natsMsg* msg) {
   220→        std::string payload{natsMsg_GetData(msg), natsMsg_GetDataLength(msg)};
   221→        // TODO: parse JSON & persist results
   222→        std::cout << "[Scanner] Received scan.completed: " << payload << '\n';
   223→    }, "scanner-completed-durable");
   224→
   225→    // Block main thread (demo purposes)
   226→    std::this_thread::sleep_for(std::chrono::hours(24));
