    47→std::string generateCorrelationId()
    48→{
    49→    static thread_local std::mt19937_64 rng{ std::random_device{}() };
    50→    static constexpr char digits[] =
    51→        "0123456789abcdef"; // 16-char representation similar to UUIDv4 sans dashes
