   127→    std::shared_ptr<ICommandExecutor> get_executor(CommandType type) const
   128→    {
   129→        std::shared_lock lk{ mutex_ };
   130→        auto it = executors_.find(type);
   131→        return it == executors_.end() ? nullptr : it->second;
   132→    }
