   176→// ---------------------------------------------------------------------------
   177→// Command Handler
   178→// ---------------------------------------------------------------------------
   179→class CommandHandler final
   180→{
   181→public:
   182→    explicit CommandHandler(std::shared_ptr<CommandRegistry> registry)
   183→        : registry_{ std::move(registry) }
   184→    {
   185→        if (!registry_) { throw std::invalid_argument("registry is nullptr"); }
   186→    }
   187→
   188→    void add_validator(std::shared_ptr<IValidator> v)
   189→    {
   190→        if (!v) { throw std::invalid_argument("validator is nullptr"); }
   191→        std::unique_lock lk{ val_mutex_ };
   192→        validators_.push_back(std::move(v));
   193→    }
   194→
   195→    void add_observer(std::shared_ptr<IObserver> o)
   196→    {
   197→        if (!o) { throw std::invalid_argument("observer is nullptr"); }
   198→        std::unique_lock lk{ obs_mutex_ };
   199→        observers_.push_back(std::move(o));
   200→    }
   201→
   202→    // Synchronous (blocking) processing
   203→    void handle(const CommandContext& ctx, const Command& cmd)
   204→    {
   205→        notify_start(ctx, cmd);
   206→        try
   207→        {
   208→            run_validation(ctx, cmd);
   209→            run_execution(ctx, cmd);
   210→            notify_success(ctx, cmd);
   211→        }
   212→        catch (const std::exception& ex)
   213→        {
   214→            notify_error(ctx, cmd, ex);
   215→            throw;      // Re-propagate to upstream orchestrator
   216→        }
   217→    }
   218→
   219→    // Asynchronous (detached) processing — returns a future
   220→    std::future<void> dispatch_async(CommandContext ctx, Command cmd)
   221→    {
   222→        return std::async(std::launch::async,
   223→                          [self = shared_from_this(), ctx = std::move(ctx), cmd = std::move(cmd)]() {
   224→                              self->handle(ctx, cmd);
   225→                          });
   226→    }
   227→
   228→private:
   229→    // Validator chain
   230→    void run_validation(const CommandContext& ctx, const Command& cmd)
   231→    {
   232→        std::shared_lock lk{ val_mutex_ };
   233→        for (const auto& v : validators_)
   234→            v->validate(ctx, cmd);
   235→    }
   236→
   237→    // Strategy execution
   238→    void run_execution(const CommandContext& ctx, const Command& cmd)
   239→    {
   240→        const auto exec = registry_->get_executor(cmd.type);
   241→        if (!exec)
   242→            throw ExecutorNotFound{ "No executor registered for " + to_string(cmd.type) };
   243→
   244→        exec->execute(ctx, cmd);
   245→    }
   246→
   247→    // Observer helpers
   248→    void notify_start(const CommandContext& ctx, const Command& cmd)   { notify(ctx, cmd, &IObserver::on_command_start,   nullptr); }
   249→    void notify_success(const CommandContext& ctx, const Command& cmd) { notify(ctx, cmd, &IObserver::on_command_success, nullptr); }
   250→    void notify_error(const CommandContext& ctx, const Command& cmd, const std::exception& ex)
   251→    {
   252→        notify(ctx, cmd, &IObserver::on_command_error, &ex);
   253→    }
   254→
   255→    void notify(const CommandContext& ctx,
   256→                const Command&        cmd,
   257→                void (IObserver::*fn)(const CommandContext&, const Command&) )
   258→    {
   259→        std::shared_lock lk{ obs_mutex_ };
   260→        for (const auto& o : observers_)
   261→        {
   262→            try { (o.get()->*fn)(ctx, cmd); }
   263→            catch (...) { /* Observer failures must never break flow */ }
   264→        }
   265→    }
   266→
   267→    void notify(const CommandContext& ctx,
   268→                const Command&        cmd,
   269→                void (IObserver::*fn)(const CommandContext&, const Command&, const std::exception&),
   270→                const std::exception* ex)
   271→    {
   272→        std::shared_lock lk{ obs_mutex_ };
   273→        for (const auto& o : observers_)
   274→        {
   275→            try { (o.get()->*fn)(ctx, cmd, *ex); }
   276→            catch (...) { /* Swallow */ }
   277→        }
   278→    }
   279→
   280→private:
   281→    // Handlers & metadata
   282→    std::shared_ptr<CommandRegistry> registry_;
   283→
   284→    // Validators & Observers
   285→    mutable std::shared_mutex                  val_mutex_;
   286→    mutable std::shared_mutex                  obs_mutex_;
   287→    std::vector<std::shared_ptr<IValidator>>   validators_;
   288→    std::vector<std::shared_ptr<IObserver>>    observers_;
   289→};
