   258→
   259→template <typename CommandT>
   260→void CommandHandler::RegisterExecutor(ExecutorFunc<CommandT> executor)
   261→{
   262→    if (!executor)
   263→        throw std::invalid_argument("CommandHandler::RegisterExecutor – executor is nullptr.");
   264→
   265→    std::lock_guard lock(m_);
   266→    const std::type_index key(typeid(CommandT));
   267→
   268→    if (executors_.contains(key))
   269→        throw std::logic_error("CommandHandler::RegisterExecutor – executor already registered.");
   270→
   271→    executors_[key] = std::make_shared<ExecutorWrapper<CommandT>>(std::move(executor));
   272→
   273→    FL360_LOG_INFO("Executor registered for command type: {}", key.name());
   274→}
