   276→inline void CommandHandler::RegisterMiddleware(MiddlewarePtr middleware)
   277→{
   278→    if (!middleware)
   279→        throw std::invalid_argument("CommandHandler::RegisterMiddleware – middleware is nullptr.");
   280→
   281→    std::lock_guard lock(m_);
   282→    middleware_pipeline_.push_back(std::move(middleware));
   283→}
   284→
   285→inline CommandResult CommandHandler::Dispatch(const std::shared_ptr<ICommand>& command)
   286→{
   287→    if (!command)
   288→        throw std::invalid_argument("CommandHandler::Dispatch – command is nullptr.");
   289→
   290→    CommandContext ctx(command);
   291→
   292→    // 1) Chain-of-Responsibility: middleware pipeline
   293→    for (const auto& mw : middleware_pipeline_)
   294→    {
   295→        bool proceed = false;
   296→        try
   297→        {
   298→            proceed = mw->Handle(ctx);
   299→        }
   300→        catch (const std::exception& ex)
   301→        {
   302→            FL360_LOG_ERROR("Middleware [{}] threw exception: {}", typeid(*mw).name(), ex.what());
   303→            return { CommandStatus::Failed, ex.what() };
   304→        }
   305→
   306→        if (!proceed)
   307→        {
   308→            return { CommandStatus::Failed, "Middleware aborted execution." };
   309→        }
   310→    }
   311→
   312→    // 2) Locate executor
   313→    std::shared_ptr<IExecutorWrapper> executor;
   314→    {
   315→        std::lock_guard lock(m_);
   316→        const std::type_index key(typeid(*command));
   317→        const auto            it = executors_.find(key);
   318→        if (it == executors_.end())
   319→        {
   320→            return { CommandStatus::Failed,
   321→                     "No executor registered for command type: " + std::string(key.name()) };
   322→        }
   323→        executor = it->second;
   324→    }
   325→
   326→    // 3) Execute
   327→    try
   328→    {
   329→        return executor->Execute(command, ctx);
   330→    }
   331→    catch (const std::exception& ex)
   332→    {
   333→        FL360_LOG_ERROR("Executor for [{}] threw exception: {}", command->name(), ex.what());
   334→        return { CommandStatus::Failed, ex.what() };
   335→    }
   336→}
