   120→/**
   121→ *  ScanCommand encapsulates “InitiateSecurityScan”.
   122→ *  After validation it emits an ‘security.scan.requested’ event to the bus.
   123→ */
   124→class ScanCommand final : public ICommand,
   125→                          public std::enable_shared_from_this<ScanCommand>
   126→{
   127→public:
   128→    using Clock      = std::chrono::system_clock;
   129→    using TimePoint  = Clock::time_point;
   130→
   131→    // A simple result wrapper to surface execution metadata.
   132→    struct Result
   133→    {
   134→        bool        ok;
   135→        std::string correlationId;
   136→        TimePoint   acceptedAt;
   137→        std::optional<std::string> reason; // filled on failure
   138→    };
   139→
   140→    using Observer = std::function<void(const ScanCommand&, const Result&)>;
   141→
   142→public:
   143→    ScanCommand(ScanContext                         ctx,
   144→                std::shared_ptr<infra::IEventBus>   bus)
   145→        : context_(std::move(ctx))
   146→        , bus_(std::move(bus))
   147→    {
   148→        if (!bus_) {
   149→            throw std::invalid_argument("ScanCommand: event bus must not be null");
   150→        }
   151→    }
   152→
   153→    std::string_view name() const noexcept override { return "InitiateSecurityScan"; }
   154→
   155→    /**
   156→     *  Executes the command: validates input, prepares event payload, and
   157→     *  publishes the event to the bus.
   158→     *
   159→     *  Throws:
   160→     *      std::runtime_error on validation or publishing errors.
   161→     */
   162→    void execute() override
   163→    {
   164→        Result res{};
   165→
   166→        try
   167→        {
   168→            validateContext();
   169→
   170→            const auto corrId = context_.correlationId.value_or(generateCorrelationId());
   171→            // Prepare a tiny JSON document.  In production we rely on
   172→            // a dedicated serialisation layer; here we keep it simple.
   173→            const std::string payload = buildPayloadJson(corrId);
   174→
   175→            domain::events::Event ev{
   176→                "security.scan.requested",
   177→                corrId,
   178→                payload
   179→            };
   180→
   181→            bus_->publish(ev);
   182→
   183→            res.ok            = true;
   184→            res.correlationId = corrId;
   185→            res.acceptedAt    = ev.timestamp;
   186→
   187→            notifyObservers(res);
   188→        }
   189→        catch (const std::exception& ex)
