   242→    std::string buildPayloadJson(std::string_view corrId) const
   243→    {
   244→        // VERY simplistic JSON composition.  Escaping omitted for brevity.
   245→        std::string json;
   246→        json.reserve(256);
   247→        json += "{";
   248→        json += "\"tenantId\":\""      + context_.tenantId + "\",";
   249→        json += "\"assetId\":\""       + context_.assetId  + "\",";
   250→        json += "\"scanDepth\":\""     + depthToString(context_.depth) + "\",";
   251→        json += "\"correlationId\":\"" + std::string(corrId) + "\"";
   252→        json += "}";
   253→        return json;
   254→    }
   255→
   256→    static std::string depthToString(ScanDepth depth)
   257→    {
   258→        switch (depth)
   259→        {
   260→            case ScanDepth::Quick:       return "quick";
   261→            case ScanDepth::Deep:        return "deep";
   262→            case ScanDepth::Continuous:  return "continuous";
   263→            default:                     return "unknown";
   264→        }
   265→    }
