   268→    // Correlation-ID helpers
   269→    // ---------------------------------------------------------------------
   270→    static std::string generateCorrelationId()
   271→    {
   272→        // UUID v4 stub—replace with a full UUID generator in production.
   273→        static constexpr char hex[] = "0123456789abcdef";
   274→        std::string uuid(36, '0');
   275→        int         rnd  = 0;
   276→        int         bits = 0;
   277→
   278→        for (std::size_t i = 0; i < uuid.size(); ++i)
   279→        {
   280→            switch (i)
   281→            {
   282→                case 8: case 13: case 18: case 23:
   283→                    uuid[i] = '-';
   284→                    break;
   285→                case 14:
   286→                    uuid[i] = '4';                    // version 4
   287→                    break;
   288→                case 19:
   289→                    uuid[i] = hex[(randomByte() & 0x3) | 0x8]; // variant
   290→                    break;
   291→                default:
   292→                    if (bits < 4)
   293→                    {
   294→                        rnd  = randomByte();
   295→                        bits = 8;
   296→                    }
   297→                    uuid[i] = hex[(rnd >> (bits -= 4)) & 0xf];
   298→            }
   299→        }
   300→        return uuid;
   301→    }
