   303→    static int randomByte()
   304→    {
   305→        // Thread-local pseudo-random byte.  In production use <random> or
   306→        // OS-supplied CSPRNG for cryptographic quality.
   307→        thread_local uint32_t state =
   308→            static_cast<uint32_t>(std::chrono::high_resolution_clock::now()
   309→                                      .time_since_epoch()
   310→                                      .count());
   311→        state = state * 1664525u + 1013904223u;
   312→        return static_cast<int>((state >> 24) & 0xFF);
   313→    }
