    52→enum class LogLevel { kDebug, kInfo, kWarn, kError };
    53→
    54→class Logger
    55→{
    56→public:
    57→    explicit Logger(std::ostream &out = std::clog) : out_(out) {}
    58→
    59→    template <typename... Args>
    60→    void log(LogLevel lvl, Args &&...args) noexcept
    61→    {
    62→        const char *lvlStr = nullptr;
    63→        switch (lvl)
    64→        {
    65→        case LogLevel::kDebug: lvlStr = "DEBUG"; break;
    66→        case LogLevel::kInfo:  lvlStr = "INFO "; break;
    67→        case LogLevel::kWarn:  lvlStr = "WARN "; break;
    68→        case LogLevel::kError: lvlStr = "ERROR"; break;
    69→        }
    70→
    71→        std::lock_guard lk(mu_);
    72→        out_ << "[" << timestamp() << "] [" << lvlStr << "] ";
    73→        (out_ << ... << std::forward<Args>(args)) << '\n';
    74→        out_.flush();
    75→    }
    76→
    77→private:
    78→    static std::string timestamp()
    79→    {
    80→        using namespace std::chrono;
    81→        const auto now   = system_clock::now();
    82→        const auto tm    = system_clock::to_time_t(now);
    83→        const auto ms    = duration_cast<milliseconds>(now.time_since_epoch()) % 1000;
    84→        std::ostringstream oss;
    85→        oss << std::put_time(std::localtime(&tm), "%F %T") << '.' << std::setfill('0') << std::setw(3) << ms.count();
    86→        return oss.str();
    87→    }
    88→
    89→    std::mutex  mu_;
    90→    std::ostream &out_;
    91→};
