   198→// ---------------------------------------------------------------------------
   199→// Thread-safe Queue
   200→// ---------------------------------------------------------------------------
   201→template <typename T>
   202→class BlockingQueue
   203→{
   204→public:
   205→    explicit BlockingQueue(std::size_t max) : capacity_(max) {}
   206→
   207→    void push(T item)
   208→    {
   209→        std::unique_lock lk(mu_);
   210→        cvFull_.wait(lk, [&] { return queue_.size() < capacity_; });
   211→        queue_.push(std::move(item));
   212→        cvEmpty_.notify_one();
   213→    }
   214→
   215→    bool pop(T &out)
   216→    {
   217→        std::unique_lock lk(mu_);
   218→        cvEmpty_.wait(lk, [&] { return !queue_.empty() || terminated_; });
   219→        if (queue_.empty()) return false; // terminated
   220→        out = std::move(queue_.front());
   221→        queue_.pop();
   222→        cvFull_.notify_one();
   223→        return true;
   224→    }
   225→
   226→    void terminate()
   227→    {
   228→        {
   229→            std::lock_guard lg(mu_);
   230→            terminated_ = true;
   231→        }
   232→        cvEmpty_.notify_all();
   233→    }
   234→
   235→private:
   236→    std::size_t                capacity_;
   237→    std::queue<T>              queue_;
   238→    std::mutex                 mu_;
   239→    std::condition_variable    cvFull_, cvEmpty_;
   240→    bool                       terminated_ {false};
   241→};
