   243→// ---------------------------------------------------------------------------
   244→// Scanner Engine (Command, Strategy, Observer, Concurrency)
   245→// ---------------------------------------------------------------------------
   246→class ScannerEngine
   247→{
   248→public:
   249→    explicit ScannerEngine(std::size_t workerCount = std::thread::hardware_concurrency())
   250→        : queue_(1024), log_(), shuttingDown_(false)
   251→    {
   252→        workerCount = std::max<std::size_t>(1, workerCount);
   253→        log_.log(LogLevel::kInfo, "Initializing ScannerEngine with ", workerCount, " workers.");
   254→
   255→        for (std::size_t i = 0; i < workerCount; ++i)
   256→        {
   257→            workers_.emplace_back([this, i] { workerLoop(i); });
   258→        }
   259→    }
   260→
   261→    ~ScannerEngine()
   262→    {
   263→        shutdown();
   264→    }
   265→
   266→    // Non-copyable
   267→    ScannerEngine(const ScannerEngine &)            = delete;
   268→    ScannerEngine &operator=(const ScannerEngine &) = delete;
   269→
   270→    void submit(const ScanCommand &cmd)
   271→    {
   272→        if (shuttingDown_.load()) throw std::runtime_error("Engine is shutting down");
   273→        queue_.push(cmd);
   274→    }
   275→
   276→    void registerObserver(std::shared_ptr<IEngineObserver> obs)
   277→    {
   278→        if (!obs) return;
   279→        std::lock_guard lk(obsMu_);
   280→        observers_.push_back(std::move(obs));
   281→    }
   282→
   283→    void shutdown()
   284→    {
   285→        bool expected = false;
   286→        if (!shuttingDown_.compare_exchange_strong(expected, true))
   287→            return; // already called
   288→
   289→        log_.log(LogLevel::kInfo, "ScannerEngine shutting down...");
   290→        queue_.terminate();
   291→
   292→        for (auto &t : workers_)
   293→            if (t.joinable()) t.join();
   294→
   295→        log_.log(LogLevel::kInfo, "All worker threads joined.");
   296→    }
   297→
   298→private:
   299→    void workerLoop(std::size_t idx)
   300→    {
   301→        try
   302→        {
   303→            while (true)
   304→            {
   305→                ScanCommand cmd;
   306→                if (!queue_.pop(cmd)) break; // queue terminated
   307→
   308→                notify(EngineEvent::kScanStarted, cmd, std::nullopt);
   309→
   310→                auto strategy = makeStrategy(cmd.intensity);
   311→
   312→                ScanResult res;
   313→                try
   314→                {
   315→                    res = strategy->execute(cmd);
   316→                    notify(EngineEvent::kScanFinished, cmd, res);
   317→                }
   318→                catch (const std::exception &ex)
   319→                {
   320→                    res.success       = false;
   321→                    res.failureReason = ex.what();
   322→                    notify(EngineEvent::kScanFailed, cmd, res);
   323→                    log_.log(LogLevel::kError, "Worker#", idx, " failed: ", ex.what());
   324→                }
   325→            }
   326→        }
   327→        catch (const std::exception &e)
   328→        {
   329→            log_.log(LogLevel::kError, "Critical error in worker#", idx, ": ", e.what());
   330→        }
   331→    }
   332→
   333→    std::unique_ptr<IScanStrategy> makeStrategy(ScanIntensity in)
   334→    {
   335→        switch (in)
   336→        {
   337→        case ScanIntensity::kLight: return std::make_unique<LightScanStrategy>(log_);
   338→        case ScanIntensity::kDeep:  return std::make_unique<DeepScanStrategy>(log_);
   339→        }
   340→        throw std::invalid_argument("Unknown intensity");
   341→    }
   342→
   343→    void notify(EngineEvent ev, const ScanCommand &cmd,
   344→                const std::optional<ScanResult> &res)
   345→    {
   346→        std::vector<std::shared_ptr<IEngineObserver>> snapshot;
   347→        {
   348→            std::lock_guard lg(obsMu_);
   349→            snapshot = observers_;
   350→        }
   351→        for (auto &o : snapshot)
   352→        {
   353→            try
   354→            {
   355→                o->onEvent(ev, cmd, res);
   356→            }
   357→            catch (const std::exception &e)
   358→            {
   359→                log_.log(LogLevel::kWarn, "Observer threw: ", e.what());
   360→            }
   361→        }
   362→    }
   363→
   364→private:
   365→    BlockingQueue<ScanCommand>                  queue_;
   366→    std::vector<std::thread>                    workers_;
   367→    std::vector<std::shared_ptr<IEngineObserver>> observers_;
   368→    std::mutex                                  obsMu_;
   369→    Logger                                      log_;
   370→    std::atomic_bool                            shuttingDown_;
   371→};
