   152→Status ServiceImpl::StreamScanLogs(ServerContext*                               ctx,
   153→                                   const proto::ScanLogStreamRequest*           request,
   154→                                   grpc::ServerWriter<proto::ScanLogEnvelope>*  writer) {
   155→    if (request->scan_id().empty()) {
   156→        return Status{grpc::INVALID_ARGUMENT, "scan_id must be provided"};
   157→    }
   158→
   159→    auto last_idx_sent = std::size_t{0};
   160→
   161→    while (!ctx->IsCancelled()) {
   162→        std::vector<std::string> snapshot;
   163→        {
   164→            std::lock_guard lk{state_mtx_};
   165→            auto it = scans_.find(request->scan_id());
   166→            if (it == scans_.end()) { return Status{grpc::NOT_FOUND, "scan not found"}; }
   167→            snapshot = it->second.logs;
   168→            if (it->second.state == ScanState::kSucceeded || it->second.state == ScanState::kFailed) {
   169→                // End stream when all logs sent after completion.
   170→                if (last_idx_sent >= snapshot.size()) { break; }
   171→            }
   172→        }
   173→
   174→        if (last_idx_sent < snapshot.size()) {
   175→            for (; last_idx_sent < snapshot.size(); ++last_idx_sent) {
   176→                proto::ScanLogEnvelope env;
   177→                env.set_message(snapshot[last_idx_sent]);
   178→                if (!writer->Write(env)) { break; }
   179→            }
   180→        }
   181→
   182→        std::this_thread::sleep_for(kLogStreamingInterval);
   183→    }
   184→
   185→    return Status::OK;
   186→}
