   192→void ServiceImpl::RunScanTask(const std::string&               scan_id,
   193→                              const std::string&               tenant_id,
   194→                              policies::IScanStrategy&         strategy,
   195→                              const std::vector<std::string>&  assets) {
   196→    auto start_time = Clock::now();
   197→    SPDLOG_INFO("[{}] Scan '{}' started ({} assets)", tenant_id, scan_id, assets.size());
   198→
   199→    auto AppendLog = [this, &scan_id](std::string msg) {
   200→        std::lock_guard lk{state_mtx_};
   201→        auto& ctx = scans_.at(scan_id);
   202→        ctx.logs.emplace_back(std::move(msg));
   203→    };
   204→
   205→    try {
   206→        strategy.execute(tenant_id, assets,
   207→                         /*progress_cb=*/
   208→                         [&](std::string_view note) { AppendLog(std::string{note}); });
   209→
   210→        {
   211→            std::lock_guard lk{state_mtx_};
   212→            scans_.at(scan_id).state = ScanState::kSucceeded;
   213→        }
   214→
   215→        metrics_->counter("scanner.scan_succeeded").inc();
   216→        event_bus_->publish(events::ScanCompleted{.scan_id = scan_id, .tenant_id = tenant_id, .success = true});
   217→        SPDLOG_INFO("[{}] Scan '{}' succeeded in {}ms", tenant_id, scan_id,
   218→                    std::chrono::duration_cast<std::chrono::milliseconds>(Clock::now() - start_time).count());
   219→    } catch (const std::exception& ex) {
   220→        {
   221→            std::lock_guard lk{state_mtx_};
   222→            scans_.at(scan_id).state = ScanState::kFailed;
   223→            scans_.at(scan_id).logs.emplace_back("ERROR: " + std::string{ex.what()});
   224→        }
   225→
   226→        metrics_->counter("scanner.scan_failed").inc();
   227→        event_bus_->publish(events::ScanCompleted{.scan_id = scan_id, .tenant_id = tenant_id, .success = false});
   228→        SPDLOG_ERROR("[{}] Scan '{}' failed: {}", tenant_id, scan_id, ex.what());
   229→    }
   230→}
