    43→/*-------------------------------------------------------------------------*/
    44→/*  General Scan Domain Types                                              */
    45→/*-------------------------------------------------------------------------*/
    46→
    47→/*  Priority of the scan request – could drive queue scheduling.           */
    48→enum class ScanPriority : std::uint8_t
    49→{
    50→    Normal = 0,
    51→    High   = 1,
    52→};
    53→
    54→/*  Global state of an individual scan operation.                          */
    55→enum class ScanState : std::uint8_t
    56→{
    57→    Pending   = 0,
    58→    Running   = 1,
    59→    Succeeded = 2,
    60→    Failed    = 3,
    61→    Cancelled = 4,
    62→};
    63→
    64→/*  Simple POD describing a scan request flowing through the domain.       */
    65→struct ScanRequest
    66→{
    67→    std::string                               tenantId;
    68→    std::string                               assetId;
    69→    std::chrono::system_clock::time_point     requestedAt;
    70→    bool                                      deepScan {false};
    71→    ScanPriority                              priority {ScanPriority::Normal};
    72→};
    73→
    74→/*  Outcome of the completed scan.                                          */
    75→struct ScanResult
    76→{
    77→    std::string                           correlationId;
    78→    std::string                           tenantId;
    79→    std::string                           assetId;
    80→    ScanState                             state        {ScanState::Succeeded};
