    85→/*---------------------------------------------------------------------------*/
    86→/*  Observer concept                                                          */
    87→/*---------------------------------------------------------------------------*/
    88→using ScanObserver = std::function<void (const ScanResult&)>;
    89→
    90→/*---------------------------------------------------------------------------*/
    91→/*  Strategy interface                                                        */
    92→/*---------------------------------------------------------------------------*/
    93→class SecurityScanStrategy
    94→{
    95→public:
    96→    virtual ~SecurityScanStrategy() = default;
    97→
    98→    /* Returns globally-unique identifier for the strategy (used in DI)  */
    99→    [[nodiscard]] virtual std::string id() const = 0;
   100→
   101→    /* Pushes a new scan onto the worker queue. Returns correlation ID.   */
   102→    virtual std::string enqueueScan(const ScanRequest& request) = 0;
   103→
   104→    /* Non-blocking poll of a completed result.                           */
   105→    [[nodiscard]] virtual std::optional<ScanResult>
   106→    pollResult(const std::string& correlationId) = 0;
   107→
   108→    /* Attempts to cancel a running or queued scan.                       */
   109→    virtual void cancelScan(const std::string& correlationId) = 0;
   110→
   111→    /* Registers an observer that is invoked once a scan finishes.        */
   112→    virtual void registerObserver(ScanObserver observer) = 0;
   113→};
