   115→/*---------------------------------------------------------------------------*/
   116→/*  Pay-As-You-Go Scan Strategy (header-only)                                 */
   117→/*---------------------------------------------------------------------------*/
   118→class PayGScanStrategy final : public SecurityScanStrategy
   119→{
   120→public:
   121→    /*  Tunables that can be loaded from YAML/JSON at runtime.            */
   122→    struct Config
   123→    {
   124→        std::chrono::milliseconds defaultTimeout  {std::chrono::seconds(30)};
   125→        double                    pricePerDeepScan{0.25};  // USD
   126→        double                    pricePerLightScan{0.10}; // USD
   127→        std::size_t               maxConcurrentScans {4};
   128→    };
   129→
   130→    /*  Callback that bills the tenant once the scan completes.           */
   131→    using BillingCallback =
   132→        std::function<void (const std::string& tenantId, double amount)>;
   133→
   134→    explicit PayGScanStrategy(
   135→            Config                       cfg           = {},
   136→            BillingCallback              billCb        = nullptr)
   137→        : config_(cfg)
   138→        , billingCb_(std::move(billCb))
   139→        , shutdown_{false}
   140→    {
   141→        spawnWorkers(config_.maxConcurrentScans);
   142→    }
   143→
   144→    PayGScanStrategy(const PayGScanStrategy&)            = delete;
   145→    PayGScanStrategy& operator=(const PayGScanStrategy&) = delete;
   146→    PayGScanStrategy(PayGScanStrategy&&)                 = delete;
   147→    PayGScanStrategy& operator=(PayGScanStrategy&&)      = delete;
   148→
   149→    ~PayGScanStrategy() override
   150→    {
   151→        /* Graceful shutdown – notify workers, then join. */
   152→        {
   153→            std::lock_guard lock(queueMtx_);
   154→            shutdown_ = true;
   155→        }
   156→        queueCv_.notify_all();
   157→        for (auto &t : workers_) { if (t.joinable()) t.join(); }
   158→    }
   159→
   160→    /*-------------------------------------------------------------------*/
   161→    /*  SecurityScanStrategy API                                         */
   162→    /*-------------------------------------------------------------------*/
   163→    [[nodiscard]] std::string id() const override
   164→    {
   165→        return "PAYG_SCANNER_V1";
   166→    }
   167→
   168→    std::string enqueueScan(const ScanRequest& request) override
   169→    {
   170→        /* Generate a deterministic UUID-like correlation id. */
   171→        const auto cid = generateCorrelationId();
   172→
   173→        {
   174→            std::lock_guard lock(queueMtx_);
   175→            if (shutdown_)
   176→                throw std::runtime_error(
   177→                        "Cannot enqueue scan: strategy shutting down.");
   178→            pending_.emplace(QueueItem{cid, request});
   179→        }
   180→        queueCv_.notify_one();
   181→        return cid;
   182→    }
   183→
   184→    std::optional<ScanResult>
   185→    pollResult(const std::string& correlationId) override
   186→    {
   187→        std::lock_guard lock(resultMtx_);
   188→        if (auto it = completed_.find(correlationId);
   189→            it != completed_.end())
   190→        {
   191→            auto result = std::move(it->second);
   192→            completed_.erase(it);
   193→            return result;
   194→        }
   195→        return std::nullopt;
   196→    }
   197→
   198→    void cancelScan(const std::string& correlationId) override
   199→    {
   200→        {
   201→            /* Quick pass – remove from pending queue if not yet started. */
   202→            std::lock_guard lock(queueMtx_);
   203→            if (cancelPendingLocked(correlationId))
   204→            {
   205→                return; // Already removed & notified observers.
   206→            }
   207→        }
   208→
   209→        /* If already running, flag it for cancellation. */
   210→        std::lock_guard lock(cancelMtx_);
   211→        cancelled_.insert(correlationId);
   212→    }
   213→
   214→    void registerObserver(ScanObserver observer) override
   215→    {
   216→        std::lock_guard lock(obsMtx_);
   217→        observers_.push_back(std::move(observer));
   218→    }
   219→
   220→private:
   221→    /*-------------------------------------------------------------------*/
   222→    /*  Internal Queue/Threading                                         */
   223→    /*-------------------------------------------------------------------*/
   224→    struct QueueItem
   225→    {
   226→        std::string correlationId;
   227→        ScanRequest request;
   228→
   229→        /* Highest priority first – normal > high => comparator reversed. */
   230→        bool operator<(const QueueItem& rhs) const noexcept
   231→        {
   232→            return static_cast<int>(request.priority) <
   233→                   static_cast<int>(rhs.request.priority);
   234→        }
   235→    };
   236→
   237→    void spawnWorkers(std::size_t poolSize)
   238→    {
   239→        for (std::size_t i = 0; i < poolSize; ++i)
   240→        {
   241→            workers_.emplace_back([this] { workerLoop(); });
   242→        }
   243→    }
   244→
   245→    void workerLoop()
   246→    {
   247→        while (true)
   248→        {
   249→            QueueItem item;
   250→            {
   251→                std::unique_lock lock(queueMtx_);
   252→                queueCv_.wait(lock, [this]
   253→                {
   254→                    return shutdown_ || !pending_.empty();
   255→                });
   256→
   257→                if (shutdown_ && pending_.empty())
   258→                    break;
   259→
   260→                item = pending_.top();
   261→                pending_.pop();
   262→            }
   263→
   264→            executeScan(item);
   265→        }
   266→    }
   267→
   268→    /*-------------------------------------------------------------------*/
   269→    /*  Scan Execution Logic                                              */
   270→    /*-------------------------------------------------------------------*/
   271→    void executeScan(const QueueItem& item)
   272→    {
   273→        const auto startedAt = std::chrono::steady_clock::now();
   274→        ScanResult result;
   275→        result.correlationId = item.correlationId;
   276→        result.tenantId      = item.request.tenantId;
   277→        result.assetId       = item.request.assetId;
   278→        result.state         = ScanState::Running;
   279→
   280→        /*  Simulated long-running scan; we simply sleep for demo.        */
   281→        const auto simulatedDuration =
   282→            item.request.deepScan ? std::chrono::seconds(5)
   283→                                  : std::chrono::seconds(2);
   284→
   285→        auto sleepUntil       = std::chrono::steady_clock::now()
   286→                              + simulatedDuration;
   287→        bool wasCancelled     = false;
   288→
   289→        while (std::chrono::steady_clock::now() < sleepUntil)
   290→        {
   291→            {
   292→                std::lock_guard lock(cancelMtx_);
   293→                if (cancelled_.erase(item.correlationId) > 0)
   294→                {
   295→                    wasCancelled = true;
   296→                    break;
   297→                }
   298→            }
   299→            std::this_thread::sleep_for(std::chrono::milliseconds(100));
   300→        }
   301→
   302→        /* Populate result. */
   303→        result.duration = std::chrono::duration_cast<std::chrono::milliseconds>(
   304→            std::chrono::steady_clock::now() - startedAt);
   305→
   306→        if (wasCancelled)
   307→        {
   308→            result.state = ScanState::Cancelled;
   309→            result.errorMessage = "Scan cancelled by user.";
   310→        }
   311→        else
   312→        {
   313→            /* 50/50 chance of “failure” to illustrate states. */
   314→            if (randomBool(0.1))
   315→            {
   316→                result.state = ScanState::Failed;
   317→                result.errorMessage = "Simulated vulnerability scan error.";
   318→            }
   319→            else
   320→            {
   321→                result.state = ScanState::Succeeded;
   322→            }
   323→        }
   324→
   325→        /* Store into completed map for polling. */
   326→        {
   327→            std::lock_guard lock(resultMtx_);
   328→            completed_.emplace(result.correlationId, result);
   329→        }
   330→
   331→        /* Trigger billing if applicable and succeeded. */
   332→        if (billingCb_ && result.state == ScanState::Succeeded)
   333→        {
   334→            const double amount =
   335→                item.request.deepScan ? config_.pricePerDeepScan
   336→                                      : config_.pricePerLightScan;
   337→            billingCb_(result.tenantId, amount);
   338→        }
   339→
   340→        /* Notify observers – executed outside locks. */
   341→        notifyObservers(result);
   342→    }
   343→
   344→    /*-------------------------------------------------------------------*/
   345→    /*  Utilities                                                         */
   346→    /*-------------------------------------------------------------------*/
   347→    static std::string generateCorrelationId()
   348→    {
   349→        thread_local std::mt19937_64 rng{std::random_device{}()};
   350→        std::uniform_int_distribution<std::uint64_t> dist;
   351→        std::uint64_t part1 = dist(rng);
   352→        std::uint64_t part2 = dist(rng);
   353→        char buffer[33];
   354→        std::snprintf(buffer, sizeof(buffer), "%016llx%016llx",
   355→                      static_cast<unsigned long long>(part1),
   356→                      static_cast<unsigned long long>(part2));
   357→        return {buffer, 32};
   358→    }
   359→
   360→    static bool randomBool(double trueProbability = 0.5)
   361→    {
   362→        thread_local std::mt19937 rng{std::random_device{}()};
   363→        std::bernoulli_distribution dist{trueProbability};
   364→        return dist(rng);
   365→    }
   366→
   367→    bool cancelPendingLocked(const std::string& correlationId)
   368→    {
   369→        /* Because std::priority_queue offers no iterator, rebuild pile. */
   370→        std::priority_queue<QueueItem> newQueue;
   371→        bool found = false;
   372→
   373→        while (!pending_.empty())
   374→        {
   375→            auto item = pending_.top();
   376→            pending_.pop();
   377→
   378→            if (item.correlationId == correlationId)
   379→            {
   380→                /* Create immediate cancellation result. */
   381→                ScanResult result;
   382→                result.correlationId = item.correlationId;
   383→                result.tenantId      = item.request.tenantId;
   384→                result.assetId       = item.request.assetId;
   385→                result.state         = ScanState::Cancelled;
   386→                result.errorMessage  = "Scan cancelled before execution.";
   387→                result.duration      = std::chrono::milliseconds{0};
   388→
   389→                {
   390→                    std::lock_guard lock(resultMtx_);
   391→                    completed_.emplace(result.correlationId, result);
   392→                }
   393→
   394→                notifyObservers(result);
   395→                found = true;
   396→                continue;
   397→            }
   398→            newQueue.push(std::move(item));
   399→        }
   400→        std::swap(pending_, newQueue);
   401→        return found;
   402→    }
   403→
   404→    void notifyObservers(const ScanResult& result)
   405→    {
   406→        std::vector<ScanObserver> snapshot;
   407→        {
   408→            std::lock_guard lock(obsMtx_);
   409→            snapshot = observers_;
   410→        }
   411→        for (auto& obs : snapshot)
   412→        {
   413→            try
   414→            {
   415→                obs(result);
   416→            }
   417→            catch (...)
   418→            {
   419→                /* Observer must never crash the domain process. */
   420→            }
   421→        }
   422→    }
   423→
   424→    /*-------------------------------------------------------------------*/
   425→    /*  Member Data                                                       */
   426→    /*-------------------------------------------------------------------*/
   427→    Config                    config_;
   428→    BillingCallback           billingCb_;
   429→
   430→    /* Worker pool. */
   431→    std::vector<std::thread>  workers_;
   432→    std::atomic<bool>         shutdown_;
   433→
   434→    /* Pending queue (priority). */
   435→    std::priority_queue<QueueItem> pending_;
   436→    std::mutex                      queueMtx_;
   437→    std::condition_variable         queueCv_;
   438→
   439→    /* Completed map. */
   440→    std::unordered_map<std::string, ScanResult> completed_;
   441→    std::mutex                                 resultMtx_;
