   107→class ContinuousScanStrategy final : public IScanStrategy,
   108→                                     public std::enable_shared_from_this<ContinuousScanStrategy>
   109→{
   110→public:
   111→    // Construction ------------------------------------------------------------
   112→    ContinuousScanStrategy(std::string                      tenantId,
   113→                           std::chrono::milliseconds        cadence,
   114→                           std::shared_ptr<IScannerService> scanner,
   115→                           std::shared_ptr<IEventBus>       bus)
   116→        : tenantId_(std::move(tenantId))
   117→        , cadence_(cadence)
   118→        , scanner_(std::move(scanner))
   119→        , bus_(std::move(bus))
   120→    {
   121→        if (!scanner_) { throw std::invalid_argument{"scanner service is null"}; }
   122→        if (!bus_)     { throw std::invalid_argument{"event bus is null"}; }
   123→        if (cadence_ < std::chrono::milliseconds{1000})
   124→        {
   125→            throw std::invalid_argument{"cadence must be >= 1s for system-safety"};
   126→        }
   127→    }
