   129→    // Rule of 5 — disallow copy; enable move ----------------------------------
   130→    ContinuousScanStrategy(const ContinuousScanStrategy&)            = delete;
   131→    ContinuousScanStrategy& operator=(const ContinuousScanStrategy&) = delete;
   132→    ContinuousScanStrategy(ContinuousScanStrategy&&)                 = default;
   133→    ContinuousScanStrategy& operator=(ContinuousScanStrategy&&)      = default;
