   136→    // IScanStrategy -----------------------------------------------------------
   137→    void start() override
   138→    {
   139→        bool expected = false;
   140→        if (!running_.compare_exchange_strong(expected, true))
   141→        {
   142→            return; // Already running, silently ignore.
   143→        }
   144→
   145→        workerThread_ = std::thread([self = shared_from_this()] { self->runLoop(); });
   146→    }
   147→
   148→    void stop() override
   149→    {
   150→        bool expected = true;
   151→        if (!running_.compare_exchange_strong(expected, false))
   152→        {
   153→            return; // Not running, nothing to do.
   154→        }
   155→
   156→        {
   157→            std::lock_guard<std::mutex> lk(cvMutex_);
   158→            // Unlock quickly after notifying to avoid potential deadlocks.
   159→        }
   160→        cv_.notify_all();
   161→
   162→        if (workerThread_.joinable())
   163→        {
   164→            workerThread_.join();
   165→        }
   166→    }
   167→
   168→    bool isRunning() const override { return running_.load(); }
   169→
   170→    std::string name() const override { return "ContinuousScanStrategy"; }
   171→
   172→    // Public API --------------------------------------------------------------
   173→    void changeCadence(std::chrono::milliseconds newCadence)
   174→    {
   175→        if (newCadence < std::chrono::milliseconds{1000})
   176→        {
   177→            throw std::invalid_argument{"cadence must be >= 1s for system-safety"};
   178→        }
   179→        {
   180→            std::lock_guard<std::mutex> lk(cvMutex_);
   181→            cadence_ = newCadence;
   182→        }
   183→        cv_.notify_all(); // Wake up worker so new cadence takes effect promptly.
   184→    }
