    19→/*
    20→ *  FortiLedger360 – Enterprise Security Suite
    21→ *  -------------------------------------------------
    22→ *  Infrastructure Layer – Event Bus
    23→ *
    24→ *  event_publisher.cpp
    25→ *
    26→ *  A high-level, thread-safe façade that encapsulates publishing DomainEvents
    27→ *  to the shared, multi-tenant event bus.  Responsibilities:
    28→ *      • payload serialization (default: JSON via nlohmann::json)
    29→ *      • automatic retry with exponential back-off
    30→ *      • futures-based asynchronous API
    31→ *      • graceful shutdown (drains queue before destructing)
    32→ *
    33→ *  NOTE:
    34→ *      ‑ An abstract IEventBus is expected to be provided by the platform team
    35→ *        (backed by NATS, Kafka, RabbitMQ, etc.).  The publisher is agnostic
    36→ *        to the actual transport.
    37→ *
    38→ *      ‑ This single compilation unit purposefully includes *minimal* stub
    39→ *        interfaces so that the file compiles in isolation while still
    40→ *        respecting the open/closed principle for production builds.
    41→ */
    42→
    43→namespace fl360::infra::eventbus
    44→{
    45→
    46→/* ----------  Light-weight stubbed dependencies  ----------------------------------------- */
    47→
    48→class IEventBus
    49→{
    50→public:
    51→    virtual ~IEventBus() = default;
    52→
    53→    /*
    54→     *  Publish a raw byte-payload to the bus.
    55→     *
    56→     *  @param routingKey   logical topic / subject (e.g. "scan.initiated")
    57→     *  @param payload      raw, serialized bytes
    58→     *  @param timeout      operation timeout – implementations MAY ignore
    59→     */
    60→    virtual void send(const std::string& routingKey,
    61→                      const std::string& payload,
    62→                      std::chrono::milliseconds timeout) = 0;
    63→};
    64→
    65→class ILogger
    66→{
    67→public:
    68→    virtual ~ILogger() = default;
    69→
    70→    virtual void info (const std::string& msg) = 0;
    71→    virtual void warn (const std::string& msg) = 0;
    72→    virtual void error(const std::string& msg) = 0;
    73→};
    74→
    75→/* ----------  Concrete, header-only JSON serializer  ------------------------------------ */
    76→
    77→struct JsonSerializer
    78→{
    79→    template <typename T>
    80→    std::string serialize(const T& obj) const
    81→    {
    82→        nlohmann::json j = obj;             // relies on ADL / to_json defined for T
    83→        return j.dump();
    84→    }
    85→};
    86→
    87→/* ----------  EventPublisher implementation  -------------------------------------------- */
    88→
    89→class EventPublisher::Impl
    90→{
    91→public:
    92→    explicit Impl(std::shared_ptr<IEventBus> bus,
    93→                  std::shared_ptr<ILogger>   logger,
    94→                  std::size_t                maxRetry,
    95→                  std::chrono::milliseconds  defaultTimeout);
    96→
    97→    ~Impl();
    98→
    99→    template <typename TEvent>
   100→    std::future<void> publishAsync(const std::string& routingKey,
   101→                                   const TEvent&     evt);
   102→
   103→    void flush();
   104→
   105→private:
   106→    struct Task final
   107→    {
   108→        std::string                      routingKey;
   109→        std::string                      payload;
   110→        std::chrono::milliseconds        timeout;
   111→        std::shared_ptr<std::promise<void>> promise;
   112→        std::size_t                      attempt {0};
   113→    };
   114→
   115→    void workerLoop();
   116→    bool send(const Task& t);
   117→    void backoff(std::size_t attempt) const;
   118→
   119→private:
   120→    std::shared_ptr<IEventBus> bus_;
   121→    std::shared_ptr<ILogger>   logger_;
   122→    JsonSerializer             serializer_;
   123→
   124→    const std::size_t          maxRetry_;
   125→    const std::chrono::milliseconds defaultTimeout_;
   126→
   127→    std::deque<Task>           queue_;
   128→    std::mutex                 queueMtx_;
   129→    std::condition_variable    queueCv_;
   130→
   131→    std::atomic<bool>          running_ {true};
   132→    std::thread                worker_;
   133→};
   134→
   135→EventPublisher::Impl::Impl(std::shared_ptr<IEventBus> bus,
   136→                           std::shared_ptr<ILogger>   logger,
   137→                           std::size_t                maxRetry,
   138→                           std::chrono::milliseconds  defaultTimeout)
   139→    : bus_(std::move(bus))
   140→    , logger_(std::move(logger))
   141→    , maxRetry_(maxRetry)
   142→    , defaultTimeout_(defaultTimeout)
   143→    , worker_(&Impl::workerLoop, this)
   144→{
   145→    if (!bus_)
   146→        throw std::invalid_argument("EventPublisher requires a non-null IEventBus");
   147→    if (!logger_)
   148→        throw std::invalid_argument("EventPublisher requires a non-null ILogger");
   149→}
   150→
   151→EventPublisher::Impl::~Impl()
   152→{
   153→    try
   154→    {
   155→        flush();
   156→        running_ = false;
   157→        queueCv_.notify_all();
   158→        if (worker_.joinable())
   159→            worker_.join();
   160→    }
   161→    catch (...)
   162→    {
   163→        // Destructor must not throw – log & swallow
   164→        // (logger_ might be already destroyed)
   165→    }
   166→}
   167→
   168→template <typename TEvent>
   169→std::future<void>
   170→EventPublisher::Impl::publishAsync(const std::string& routingKey,
   171→                                   const TEvent&     evt)
   172→{
   173→    if (!running_)
   174→        throw std::runtime_error("EventPublisher is shutting down");
   175→
   176→    Task task;
   177→    task.routingKey = routingKey;
   178→    task.payload    = serializer_.serialize(evt);
   179→    task.timeout    = defaultTimeout_;
   180→    task.promise    = std::make_shared<std::promise<void>>();
   181→
   182→    {
   183→        std::lock_guard<std::mutex> lg(queueMtx_);
   184→        queue_.emplace_back(std::move(task));
   185→    }
   186→    queueCv_.notify_one();
   187→
   188→    return task.promise->get_future();
   189→}
   190→
   191→void EventPublisher::Impl::flush()
   192→{
   193→    std::unique_lock<std::mutex> ul(queueMtx_);
   194→    queueCv_.wait(ul, [this] { return queue_.empty(); });
   195→}
   196→
   197→void EventPublisher::Impl::workerLoop()
   198→{
   199→    while (running_)
   200→    {
   201→        Task task;
   202→        {
   203→            std::unique_lock<std::mutex> ul(queueMtx_);
   204→            queueCv_.wait(ul, [this] { return !queue_.empty() || !running_; });
   205→
   206→            if (!running_ && queue_.empty())
   207→                break;
   208→
   209→            task = std::move(queue_.front());
   210→            queue_.pop_front();
   211→        }
   212→
   213→        if (!send(task))
   214→        {
   215→            if (task.attempt < maxRetry_)
   216→            {
   217→                ++task.attempt;
   218→                backoff(task.attempt);
   219→
   220→                std::lock_guard<std::mutex> lg(queueMtx_);
   221→                queue_.push_back(std::move(task)); // push to tail (FIFO)
   222→                queueCv_.notify_one();
   223→            }
   224→            else
   225→            {
   226→                std::string err =
   227→                    "Failed to publish after " + std::to_string(maxRetry_) +
   228→                    " attempts. Dropping message for route '" + task.routingKey + "'";
   229→                logger_->error(err);
   230→
   231→                task.promise->set_exception(
   232→                    std::make_exception_ptr(std::runtime_error(err)));
   233→            }
   234→        }
   235→        else
   236→        {
   237→            task.promise->set_value();
   238→        }
   239→    }
   240→}
   241→
   242→bool EventPublisher::Impl::send(const Task& t)
   243→{
   244→    try
   245→    {
   246→        bus_->send(t.routingKey, t.payload, t.timeout);
   247→        return true;
   248→    }
   249→    catch (const std::exception& ex)
   250→    {
   251→        std::ostringstream oss;
   252→        oss << "Publish attempt " << (t.attempt + 1)
   253→            << " to '" << t.routingKey
   254→            << "' failed: " << ex.what();
   255→        logger_->warn(oss.str());
   256→        return false;
   257→    }
   258→    catch (...)
   259→    {
   260→        logger_->warn("Publish attempt failed: <unknown exception>");
   261→        return false;
   262→    }
   263→}
   264→
   265→void EventPublisher::Impl::backoff(std::size_t attempt) const
   266→{
   267→    // Simple exponential back-off with jitter
   268→    using namespace std::chrono_literals;
   269→    const auto base     = 50ms;
   270→    const auto cap      = 2s;
   271→    auto delay          = base * (1ULL << attempt);
   272→    if (delay > cap) delay = cap;
   273→
   274→    std::this_thread::sleep_for(delay);
   275→}
