   277→/* ----------  EventPublisher public façade  --------------------------------------------- */
   278→
   279→EventPublisher::EventPublisher(std::shared_ptr<IEventBus> bus,
   280→                               std::shared_ptr<ILogger>   logger,
   281→                               std::size_t                maxRetry,
   282→                               std::chrono::milliseconds  defaultTimeout)
   283→    : impl_(std::make_unique<Impl>(std::move(bus),
   284→                                   std::move(logger),
   285→                                   maxRetry,
   286→                                   defaultTimeout))
   287→{ }
   288→
   289→EventPublisher::~EventPublisher() = default;
   290→
   291→void EventPublisher::flush()
   292→{
   293→    impl_->flush();
   294→}
   295→
   296→template <typename TEvent>
   297→std::future<void> EventPublisher::publishAsync(const std::string& routingKey,
   298→                                               const TEvent&     event)
   299→{
   300→    return impl_->publishAsync(routingKey, event);
   301→}
