   216→void EventConsumer::consumeLoop() {
   217→    log_->info("EventConsumer started (pollTimeout={}ms)",
   218→               config_.pollTimeout.count());
   219→
   220→    // Thread pool for event processing
   221→    std::vector<std::thread> processingThreads;
   222→    std::mutex               queueMutex;
   223→    std::condition_variable  queueCond;
   224→    std::deque<cppkafka::Message> messageQueue;
   225→    std::atomic<bool>        processingStop{ false };
   226→
   227→    // Worker lambda
   228→    auto workerFn = [&]() {
   229→        while (!processingStop.load()) {
   230→            cppkafka::Message msg;
   231→            {
   232→                std::unique_lock<std::mutex> lock(queueMutex);
   233→                queueCond.wait(lock, [&]() {
   234→                    return processingStop.load() || !messageQueue.empty();
   235→                });
   236→                if (processingStop.load() && messageQueue.empty()) {
   237→                    return;
   238→                }
   239→                msg = std::move(messageQueue.front());
   240→                messageQueue.pop_front();
   241→            }
   242→
   243→            // ------------------------------------------------------------
   244→            //  Per-message processing
   245→            // ------------------------------------------------------------
   246→            try {
   247→                if (msg.get_key()) {
   248→                    spdlog::trace("Consumed key: {}", msg.get_key());
   249→                }
   250→
   251→                nlohmann::json payload = nlohmann::json::parse(msg.get_payload());
   252→                const auto&    eventType = payload.at("eventType").get_ref<const std::string&>();
   253→                dispatcher_->dispatch(eventType, payload);
   254→
   255→                // Commit offset manually (synchronously for simplicity)
   256→                if (!config_.enableAutoCommit) {
   257→                    consumer_.commit(msg);
   258→                }
   259→            }
   260→            catch (const nlohmann::json::parse_error& ex) {
   261→                log_->error("JSON parse error at offset {}: {}", msg.get_offset(), ex.what());
   262→            }
   263→            catch (const nlohmann::json::out_of_range& ex) {
   264→                log_->error("Missing required JSON fields: {}", ex.what());
   265→            }
   266→            catch (const std::exception& ex) {
   267→                log_->error("Unhandled exception while processing message: {}", ex.what());
   268→            }
   269→        }
   270→    };
   271→
   272→    // Spawn processing threads
   273→    for (size_t i = 0; i < config_.maxProcessingThreads; ++i) {
   274→        processingThreads.emplace_back(workerFn);
   275→    }
   276→
   277→    // Main polling loop
   278→    while (running_.load()) {
   279→        try {
   280→            auto msg = consumer_.poll(config_.pollTimeout);
   281→
   282→            if (!msg) {
   283→                continue; // timeout
   284→            }
   285→
   286→            if (msg.get_error()) {
   287→                // End-of-partition or error
   288→                if (!msg.is_eof()) {
   289→                    log_->error("Kafka error: {}", msg.get_error());
   290→                }
   291→                continue;
   292→            }
   293→
   294→            // Enqueue message
   295→            {
   296→                std::lock_guard<std::mutex> lock(queueMutex);
   297→                messageQueue.emplace_back(std::move(msg));
   298→            }
   299→            queueCond.notify_one();
   300→        }
   301→        catch (const cppkafka::HandleException& ex) {
   302→            log_->error("Kafka exception: {}", ex.what());
   303→        }
   304→        catch (const std::exception& ex) {
   305→            log_->error("Unexpected exception: {}", ex.what());
   306→        }
   307→    }
   308→
   309→    // Signal processing threads to finish
   310→    {
   311→        std::lock_guard<std::mutex> lock(queueMutex);
   312→        processingStop.store(true);
   313→    }
   314→    queueCond.notify_all();
   315→
   316→    // Join processing threads
   317→    for (auto& t : processingThreads) {
   318→        if (t.joinable()) {
   319→            t.join();
   320→        }
   321→    }
   322→}
