   196→        // Pack message & dispatch onto event bus
   197→        try {
   198→            publisher_->publish("commands", request->SerializeAsString());
   199→            response->set_status(gateway::v1::CommandResponse::ACCEPTED);
   200→            response->set_message("Command queued for execution");
