    77→namespace fl360::scanner {
    78→
    79→struct ScanTask
    80→{
    81→    std::string tenant_id;
    82→    std::string target_uri;
    83→    std::chrono::system_clock::time_point requested_at;
    84→};
    85→
    86→class Engine final
    87→{
    88→public:
    89→    explicit Engine(std::size_t worker_threads)
    90→        : stop_flag_{false}
    91→    {
    92→        SPDLOG_INFO("Bootstrapping scanning engine with {} workers …", worker_threads);
    93→        for (std::size_t i = 0; i < worker_threads; ++i)
    94→        {
    95→            workers_.emplace_back([this, i] { loop(i); });
    96→        }
    97→    }
    98→
    99→    ~Engine()
   100→    {
   101→        shutdown();
   102→    }
   103→
   104→    void enqueue(ScanTask task)
   105→    {
   106→        {
   107→            std::lock_guard lk(queue_mtx_);
   108→            queue_.emplace_back(std::move(task));
   109→        }
   110→        cv_.notify_one();
   111→    }
   112→
   113→    void shutdown()
   114→    {
   115→        bool expected = false;
   116→        if (!stop_flag_.compare_exchange_strong(expected, true))
   117→            return;  // Already shutting down
   118→
   119→        cv_.notify_all();
   120→        for (std::thread& t : workers_)
   121→            if (t.joinable())
   122→                t.join();
   123→        SPDLOG_INFO("Scanning engine exited gracefully.");
   124→    }
   125→
   126→private:
   127→    void loop(std::size_t id)
   128→    {
   129→        while (!stop_flag_)
   130→        {
   131→            std::optional<ScanTask> maybe;
   132→            {
   133→                std::unique_lock lk(queue_mtx_);
   134→                cv_.wait(lk, [this] { return stop_flag_ || !queue_.empty(); });
   135→                if (stop_flag_) break;
   136→                maybe = std::move(queue_.front());
   137→                queue_.pop_front();
   138→            }
   139→
   140→            if (maybe)
   141→                performScan(*maybe, id);
   142→        }
   143→    }
   144→
   145→    void performScan(const ScanTask& t, std::size_t worker_id)
   146→    {
   147→        SPDLOG_INFO("[worker {}] Starting scan for tenant={} target={}",
   148→                    worker_id, t.tenant_id, t.target_uri);
   149→
   150→        // Simulate I/O-bound scanning workload
   151→        std::this_thread::sleep_for(std::chrono::seconds(2));
   152→
   153→        // TODO: Send result to Event-Bus
   154→        SPDLOG_INFO("[worker {}] Completed scan for target={}", worker_id, t.target_uri);
   155→    }
   156→
   157→    std::atomic_bool stop_flag_;
   158→    std::condition_variable cv_;
   159→    std::mutex queue_mtx_;
   160→    std::deque<ScanTask> queue_;
   161→    std::vector<std::thread> workers_;
   162→};
