   224→struct AppConfig
   225→{
   226→    std::string listen_addr             = "0.0.0.0";
   227→    std::uint16_t listen_port           = 50051;
   228→    std::size_t  worker_threads         = std::thread::hardware_concurrency();
   229→    std::filesystem::path tls_cert_path = "scanner.crt";
   230→    std::filesystem::path tls_key_path  = "scanner.key";
   231→};
   232→
   233→static AppConfig loadConfig(const std::filesystem::path& file)
   234→{
   235→    AppConfig cfg;
   236→    if (file.empty())
   237→        return cfg;
   238→
   239→    try
   240→    {
   241→        YAML::Node root = YAML::LoadFile(file.string());
   242→        if (root["listen_addr"])
   243→            cfg.listen_addr = root["listen_addr"].as<std::string>();
   244→        if (root["listen_port"])
   245→            cfg.listen_port = root["listen_port"].as<uint16_t>();
   246→        if (root["worker_threads"])
   247→            cfg.worker_threads = root["worker_threads"].as<std::size_t>();
   248→        if (root["tls_cert"])
   249→            cfg.tls_cert_path = root["tls_cert"].as<std::string>();
   250→        if (root["tls_key"])
   251→            cfg.tls_key_path = root["tls_key"].as<std::string>();
   252→    }
   253→    catch (const YAML::Exception& ex)
   254→    {
   255→        SPDLOG_WARN("Failed to parse config file {}: {}", file.string(), ex.what());
   256→    }
   257→    return cfg;
   258→}
