   271→/*--------------------------------------------------------------------
   272→ * Helpers
   273→ *-------------------------------------------------------------------*/
   274→static std::shared_ptr<::grpc::ServerCredentials>
   275→buildServerCredentials(const AppConfig& cfg)
   276→{
   277→    // Load key/cert into string
   278→    std::ifstream cert_in(cfg.tls_cert_path, std::ios::binary);
   279→    std::ifstream key_in(cfg.tls_key_path,  std::ios::binary);
   280→
   281→    if (!cert_in || !key_in)
   282→    {
   283→        SPDLOG_ERROR("Failed to read TLS cert/key files – falling back to insecure creds!");
   284→        return ::grpc::InsecureServerCredentials();
   285→    }
   286→
   287→    std::string cert((std::istreambuf_iterator<char>(cert_in)), {});
   288→    std::string key((std::istreambuf_iterator<char>(key_in)), {});
   289→
   290→    ::grpc::SslServerCredentialsOptions::PemKeyCertPair pkcp{key, cert};
   291→    ::grpc::SslServerCredentialsOptions ssl_ops;
   292→    ssl_ops.pem_key_cert_pairs.push_back(pkcp);
   293→    ssl_ops.client_certificate_request =
   294→        GRPC_SSL_REQUEST_AND_REQUIRE_CLIENT_CERT_BUT_DONT_VERIFY;
   295→
   296→    return ::grpc::SslServerCredentials(ssl_ops);
   297→}
