   302→int main(int argc, char* argv[])
   303→{
   304→    // -------------------- CLI parsing --------------------
   305→    cxxopts::Options options("scanner_svc",
   306→                             "FortiLedger360 – Real-time Vulnerability Scanner");
   307→    options.add_options()
   308→        ("c,config",    "Path to YAML config file", cxxopts::value<std::string>())
   309→        ("log-level",   "Log level (trace|debug|info|warn|error)",
   310→                        cxxopts::value<std::string>()->default_value("info"))
   311→        ("h,help",      "Print usage");
   312→
   313→    auto result = options.parse(argc, argv);
   314→
   315→    if (result.count("help"))
   316→    {
   317→        fmt::print("{}\n", options.help());
   318→        return EXIT_SUCCESS;
   319→    }
   320→
   321→    const auto log_level = spdlog::level::from_str(result["log-level"].as<std::string>());
   322→    spdlog::set_level(log_level);
   323→
   324→    // -------------------- Load configuration --------------------
   325→    std::filesystem::path cfg_file;
   326→    if (result.count("config"))
   327→        cfg_file = result["config"].as<std::string>();
   328→
   329→    AppConfig cfg = loadConfig(cfg_file);
   330→
   331→    SPDLOG_INFO("Listen on {}:{}", cfg.listen_addr, cfg.listen_port);
   332→    SPDLOG_INFO("Worker threads: {}", cfg.worker_threads);
   333→
   334→    // -------------------- Boot scanning engine --------------------
   335→    auto engine = std::make_shared<fl360::scanner::Engine>(cfg.worker_threads);
   336→
   337→    // -------------------- Build gRPC server --------------------
   338→    const std::string addr = fmt::format("{}:{}", cfg.listen_addr, cfg.listen_port);
   339→
   340→    fl360::scanner::ScannerServiceImpl svc(engine);
   341→    ::grpc::ServerBuilder builder;
   342→    builder.AddListeningPort(addr, buildServerCredentials(cfg));
   343→    builder.RegisterService(&svc);
   344→
   345→    std::unique_ptr<::grpc::Server> server(builder.BuildAndStart());
   346→    if (!server)
   347→    {
   348→        SPDLOG_CRITICAL("Failed to start gRPC server. Exiting …");
   349→        return EXIT_FAILURE;
   350→    }
   351→    SPDLOG_INFO("Scanner service started and awaiting requests.");
   352→
   353→    // -------------------- Setup signal handling --------------------
   354→    std::signal(SIGINT,  handleSignal);
   355→    std::signal(SIGTERM, handleSignal);
   356→
   357→    // Block until termination signal
   358→    while (!g_terminate)
   359→        std::this_thread::sleep_for(std::chrono::milliseconds(200));
   360→
   361→    // Stop gRPC server
   362→    SPDLOG_INFO("Shutting down gRPC server …");
   363→    server->Shutdown();
   364→    // Wait until all RPCs have completed
   365→    server->Wait();
   366→
   367→    // Stop engine
   368→    engine->shutdown();
